So we could add a last-concept to the generic stream master/slave VCI. 

Making the following changes to stream_master:
```vhdl
  -- NOTE: Added last parameter
  -- Push a data value to the stream
  procedure push_stream(signal net : inout network_t;
                        stream : stream_master_t;
                        data : std_logic_vector;
                        last : boolean := false);
```

Making the following additions/changes to stream_slave:
```vhdl
  -- NOTE: New procedure in addition to old
  procedure pop_stream(signal net : inout network_t;
                       stream : stream_slave_t;
                       variable data : out std_logic_vector;
                       variable last : out boolean);

  -- NOTE: New procedure in addition to old
  procedure await_pop_stream_reply(signal net : inout network_t;
                                   variable reference : inout stream_reference_t;
                                   variable data : out std_logic_vector;
                                   variable last : out boolean);

  -- NOTE: Added last parameter
  -- Blocking: read stream and check result against expected value
  procedure check_stream(signal net : inout network_t;
                         stream : stream_slave_t;
                         expected : std_logic_vector;
                         last : boolean := false;
                         msg : string := "");
```

